oxy_webhelp_navlinks = {"mysql_recovery-d30753e31562":{"topics":[{"title":"MySQL recovery options","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides flexible and versatile options for MySQL recovery. You         can recover either the entire MySQL instance or specific databases, ensuring rapid and         granular data restoration from secure, immutable backups.<\/p>","href":"mysql\/mysql_recovery_options.html","attributes":{"data-id":"mysql_recovery_options"},"menu":{"hasChildren":false},"tocID":"mysql_recovery_options-d30753e31576","topics":[]},{"title":"Creating a restore mount point for MySQL instance snapshots","shortdesc":"<p class=\"shortdesc\">Create a mount point to restore your MySQL instance snapshots by mounting a snapshot         of backup data to the mount point using NFS.<\/p>","href":"mysql\/mysql_creating_restore_mp_instance_snap.html","attributes":{"data-id":"mysql_creating_restore_mp_instance_snap"},"menu":{"hasChildren":false},"tocID":"mysql_creating_restore_mp_instance_snap-d30753e31589","topics":[]},{"title":"Restoring MySQL snapshots to the original instance","shortdesc":"<p class=\"shortdesc\">Restore MySQL snapshots to the original MySQL instance from which the backup was         taken.<\/p>","href":"mysql\/mysql_restoring_snap_original_instance.html","attributes":{"data-id":"mysql_restoring_snap_original_instance"},"menu":{"hasChildren":false},"tocID":"mysql_restoring_snap_original_instance-d30753e31600","topics":[]},{"title":"Restoring MySQL snapshots to a new instance","shortdesc":"<p class=\"shortdesc\">Restore the MySQL instance snapshots to a newly created MySQL instance.<\/p>","href":"mysql\/mysql_restoring_snap_new_instance.html","attributes":{"data-id":"mysql_restoring_snap_new_instance"},"menu":{"hasChildren":false},"tocID":"mysql_restoring_snap_new_instance-d30753e31611","topics":[]},{"title":"Recovering MySQL instances automatically","shortdesc":"<p class=\"shortdesc\">Use the automated recovery workflow to restore a MySQL instance as a standalone         setup. This process simplifies recovery by automating manual steps required for         instance-level recovery.<\/p>","href":"mysql\/mysql_recovering_instances_auto.html","attributes":{"data-id":"mysql_recovering_instances_auto"},"menu":{"hasChildren":false},"tocID":"mysql_recovering_instances_auto-d30753e31622","topics":[]},{"title":"Recovering MySQL databases automatically","shortdesc":"<p class=\"shortdesc\">Use the automated recovery workflow to restore specific MySQL databases within an         instance. This process automates the manual mount-and-script steps required for         database-level recovery.<\/p>","href":"mysql\/mysql_recovering_databases_auto.html","attributes":{"data-id":"mysql_recovering_databases_auto"},"menu":{"hasChildren":false},"tocID":"mysql_recovering_databases_auto-d30753e31633","next":"mysql_recovering_databases_auto-d30753e31633"},{"title":"Creating a restore mount point for MySQL database snapshots","shortdesc":"<p class=\"shortdesc\">Create a mount point for restoring your MySQL database snapshots by mounting a         snapshot of backup data to the mount point using NFS.<\/p>","href":"mysql\/mysql_creating_restore_mp_db_snap.html","attributes":{"data-id":"mysql_creating_restore_mp_db_snap"},"menu":{"hasChildren":false},"tocID":"mysql_creating_restore_mp_db_snap-d30753e31655","topics":[]},{"title":"Restoring MySQL snapshots to the original database","shortdesc":"<p class=\"shortdesc\">Restore the MySQL snapshots to the original MySQL database from which the backup was         taken.<\/p>","href":"mysql\/mysql_restoring_snap_original_db.html","attributes":{"data-id":"mysql_restoring_snap_original_db"},"menu":{"hasChildren":false},"tocID":"mysql_restoring_snap_original_db-d30753e31666","topics":[]},{"title":"Restoring MySQL snapshots to a new database","shortdesc":"<p class=\"shortdesc\">Restore the MySQL snapshots to a new MySQL database.<\/p>","href":"mysql\/mysql_restoring_snap_new_db.html","attributes":{"data-id":"mysql_restoring_snap_new_db"},"menu":{"hasChildren":false},"tocID":"mysql_restoring_snap_new_db-d30753e31677","topics":[]},{"title":"Unmounting the restore mount point after MySQL snapshot recovery","shortdesc":"<p class=\"shortdesc\">After recovering MySQL snapshots, unmount the restore mount point to remove the         metadata associated with the selected MySQL cluster.<\/p>","href":"mysql\/mysql_unmounting_restore_mp.html","attributes":{"data-id":"mysql_unmounting_restore_mp"},"menu":{"hasChildren":false},"tocID":"mysql_unmounting_restore_mp-d30753e31688","topics":[]}]}};